-- в”Ђв”Ђ Avocode в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Avocode was a design handoff tool that let developers inspect Sketch, Photoshop, XD, and Figma files for specs, assets, and code snippets; the product was discontinued (sunset) on October 1, 2023 after its 2021 acquisition by Ceros.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (product discontinued; formerly an independent company acquired by Ceros)$q$, company_size),
  headquarters = COALESCE($q$Formerly Prague, Czech Republic; parent company Ceros is headquartered in New York, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Avocode (2026): What Happened to This Design Handoff Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Avocode was a Sketch, Photoshop, and Figma design handoff tool. Learn its history, features, and why it was discontinued by parent company Ceros in 2023.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Avocode was a design-to-development handoff tool founded in 2015 (some sources cite 2014) in Prague, Czech Republic, by Vu Hoang Anh, Petr Brzek, and Martin Duris, a team that had previously built the popular CSS Hat Photoshop plugin together. Avocode raised roughly 1 million dollars in a seed round in 2016 and grew into a tool used by developers to inspect designs exported from Sketch, Photoshop, Adobe XD, and later Figma, extracting CSS, measurements, colors, fonts, and assets directly from design files without needing the original design application installed. It functioned similarly to competitors like Zeplin and the built-in inspect features later added natively to Figma. On October 20, 2021, design-to-code and content platform Ceros announced it had acquired Avocode, aiming to combine Avocode's design-inspection technology with Ceros's own no-code content creation tools. Avocode continued operating as a product for roughly two more years under Ceros ownership. However, Ceros subsequently decided to consolidate its product line around newer tools, and Avocode was officially sunset on October 1, 2023; the avocode.com website itself now states the product has been retired and directs former users toward other Ceros offerings such as Studio and MarkUp rather than continuing to sell or support Avocode. As of 2026, Avocode is not available for purchase, is not receiving updates, and existing accounts are not expected to be supported going forward. It is important for anyone researching Avocode today to understand it as a discontinued, historical product rather than an active SaaS tool; teams looking for equivalent functionality (design file inspection, spec extraction, and code snippet generation for handoff between designers and developers) should evaluate active alternatives such as Figma's native Dev Mode, Zeplin, or UXPin, none of which are the direct successor to Avocode despite some confusion in search results between Avocode (acquired by Ceros) and the separately owned UXPin (acquired by Xenon Partners in 2020). No current pricing exists because the product is no longer sold.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '08f28219-ca73-42dd-9c5f-17577ab1c841';

